local LModel = LModel

---@class BadgeInfo
local BadgeInfo = LxClass("BadgeInfo",nil)
function BadgeInfo:BadgeInfo(pb)
	self:SetData(pb)
end
--灵魂数据类
function BadgeInfo:SetData(pb)
	self.refId = pb.refId
	self.star = pb.star--星级表refId
	self.wearNum = 0--穿戴数量
	local slotToHero = {}
	local heroToSlot = {}
	local oldSlotToHero = self.slotToHeroWears
	for _, value in ipairs(pb.wears) do
		self.wearNum = self.wearNum+1
		if not slotToHero[value.slot] then slotToHero[value.slot] = {} end
		table.insert(slotToHero[value.slot],{slot = value.slot,heroId = value.heroId})
		heroToSlot[value.heroId] = value.slot

		if not gModelBadge.heroWearsBadges[value.heroId] then gModelBadge.heroWearsBadges[value.heroId] = {} end
		gModelBadge.heroWearsBadges[value.heroId][pb.refId]=value.slot
	end
	-- local isChange = false
	--穿戴数据变化时对比更新
	for slot, wears in pairs(oldSlotToHero or {}) do
		for _, value in ipairs(wears) do
			if not heroToSlot[value.heroId] then
				gModelBadge.heroWearsBadges[value.heroId][self.refId] = nil
			end
		end
	end
	---@type table<number,number> 佩戴信息：槽位={槽位，英雄ID}
	self.slotToHeroWears = slotToHero
	self.starRef = GameTable.BadgeStarRef[self.star]

end
--灵魂等级
function BadgeInfo:GetBadgeLv()
	return self.starRef and self.starRef.collegeLv or 0
end
--灵魂星级
function BadgeInfo:GetBadgeStar()
	return self.starRef and self.starRef.star or 0
end
--升星配置
function BadgeInfo:GetStarRef()
	return self.starRef
end
--灵魂配置
function BadgeInfo:GetBadgeRef()
	return GameTable.BadgeRef[self.refId]
end
--剩余佩戴次数
function BadgeInfo:CanWearNum()
	return self.starRef and (self.starRef.wearNum<0 and 10000000  or self.starRef.wearNum-self.wearNum) or 0
end
--升星红点
function BadgeInfo:UpStarRedPoint(qualityNum)
	local starCfg = self:GetStarRef()
	if starCfg.nextStar<0 then return false end
	local item = LxDataHelper.ParseItem_4(starCfg.nextCostBase)
	if not gModelGeneral:CheckItemEnough(item.itemId,item.itemNum,false) then
		return false
	end
	local selCost = string.split(starCfg.nextCostSpecial,",")
	local needCost = nil
	local needNum = 0
	local quality = nil
	if selCost and #selCost>0 then
		for _, value in pairs(selCost) do
			needCost = string.split(value,"=")
			quality = tonumber(needCost[1])
			needNum = tonumber(needCost[2])
			if (qualityNum[quality] or 0)<needNum then
				return false
			end
		end
	end
	return true

end
