--佩戴  通过 BadgeBagResp 协议刷新
function ModelBadge:BadgeWearReq(type,heroId,wear)
	local proto = LProtoHelper.CreateProto(LProtoIds.BadgeWearReq)
	--1=装配（一键装配时wear空着），2=卸载（wear传需要卸载的数据），3=一键卸载当前英雄所有（wear可不传）
	proto.type = type
	proto.heroId = heroId
	if wear then
		proto.wear.refId = wear.refId
		proto.wear.slot = wear.slot
		if wear.tarHeroId then proto.wear.target = wear.tarHeroId end
	end

	SendMessage(proto,LProtoIds.BadgeWearReq)
end
