function ModelBadge:BadgeSelectRewardReq(randomReward,selectIndex)--选择的自选奖励下标（1=固定奖励1,2=固定奖励2,3=随机奖励）
	local proto = LProtoHelper.CreateProto(LProtoIds.BadgeSelectRewardReq)
	for _, value in ipairs(randomReward) do
		if value.refId then
			proto.randomReward:append(value.refId)
		end
	end
	proto.selectIndex = selectIndex or 0
	SendMessage(proto,LProtoIds.BadgeSelectRewardReq)
end
