function ModelBadge:OnBadgeBagResp(pb)
	self.level = pb.level
	for _, value in ipairs(pb.badge) do
		self:SetBadgeInfo(value)
	end
	FireEvent(EventNames.BADGE_BAG_UPDATE)
end

function ModelBadge:OnBadgeStrengthenStarResp(pb)
	if pb.badge then
		self.level = pb.level
		local refId = pb.badge.refId
		local badge = self:GetBadgeInfo(refId)
		local oldStarRef = badge and badge:GetStarRef()
		self:SetBadgeInfo(pb.badge)
		if not badge then --激活
			GF.OpenWnd("UIBrandActivaSuccess",{refId = refId, oldStarId = nil})
		else--升星
			GF.OpenWnd("UIBrandActivaSuccess",{refId = refId,oldStarId = oldStarRef.refId})
		end
		FireEvent(EventNames.BADGE_BAG_UPDATE,true)
	end
end
function ModelBadge:OnBadgeWearResp(pb)
	FireEvent(EventNames.BADGE_BAG_UPDATE_WEAR)
end
