function ModelBadge:SetBadgeDropInfo(pb)
	self.round = pb.round
	self.endTime = pb.endTime
	self.free = pb.free
	self.daySum = pb.daySum
	self.accumulate = pb.accumulate
	self.upPool = {}--up提升的奖池refId
	for _, value in ipairs(pb.upPool) do
		table.insert(self.upPool,value)
	end
	self.randomReward = {}--已选择的随机奖励（奖池表refId）
	for _, value in ipairs(pb.randomReward) do
		table.insert(self.randomReward,value)
	end

	self.fixedReward = {}--固定奖励（奖池表refId）
	for _, value in ipairs(pb.fixedReward) do
		table.insert(self.fixedReward,value)
	end
	self.selectIndex = pb.selectIndex
	FireEvent(EventNames.BADGE_CALL_UPDATE)
end
