-----配置
function ModelBadge:GetBadgeStarRef(refId)
	if not self.badgeStarRefs then
		local lists = {}
		self.badgeStarRefs = lists
		local starRefs = GameTable.BadgeStarRef
		for _, value in pairs(starRefs) do
			if not lists[value.type] then lists[value.type] = {} end
			table.insert(lists[value.type],value)
		end
		for _,lis  in pairs(lists) do
			table.sort(lis,function(a, b) return a.star<b.star end)
		end
	end
	return self.badgeStarRefs[refId]
end

function ModelBadge:GetBadgeSlotConfig(page)
	if not self.slotRefs then
		self.slotRefs = {}
		local posConfigs = GameTable.BadgePositionRef
		for _, value in pairs(posConfigs) do
			if not self.slotRefs[value.page] then self.slotRefs[value.page] = {} end
			table.insert(self.slotRefs[value.page],value)
		end
		for _, list in pairs(self.slotRefs) do
			table.sort(list,function(a, b) return a.refId<b.refId end)
		end
	end
	return self.slotRefs[page]
end
--英雄灵魂槽位是否解锁
function ModelBadge:IsLockBadgeSlot(heroId,page,slot)
	local slotRef = self:GetBadgeSlotConfig(page) or {}
	local condi = slotRef[slot]
	local condiStr = string.split(condi.star,"=")
	if tonumber(condiStr[1]) ==1 then --英雄星级
		local hero = gModelHero:GetHeroById(heroId)
		if hero and tonumber(condiStr[2]) > hero._star then
			return false,string.replace(ccClientText(47513),condiStr[2])
		end
		return true
	else -- 考古阶级

	end
end
--是否有可以穿戴的灵魂(有次数&没穿带)
function ModelBadge:HasCanWearBadge(heroId)
	local badges = self.badgeBagList
	for refId, badge in pairs(badges) do
		if badge and badge:CanWearNum()>0 and not self:GetBadgeIdWearPos(heroId,refId) then
			return true, refId
		end
	end
end
--获取灵魂等级属性
function ModelBadge:GetBadgeLvAttrs(addTarget)
	local badgePerLvAttr = GameTable.BadgeConfigRef.badgePerLvAttr
	local lvAttr = LxDataHelper.ParseAttrList(badgePerLvAttr)
	local lv = self.level
	local targetAttr = {}
	if addTarget then targetAttr = self:GetBadgeTargetAttr() end
	local exitAtrr = {}
	for _, attr in pairs(lvAttr) do
		attr.value = attr.value*lv
		if targetAttr[attr.refId..attr.type] then
			local at = targetAttr[attr.refId..attr.type]
			targetAttr[attr.refId..attr.type] = nil
			attr.value = attr.value+at.value
		end
		exitAtrr[attr.refId..attr.type] = true
	end
	if addTarget then
		for _, value in pairs(targetAttr) do
			table.insert(lvAttr,value)
			exitAtrr[value.refId..value.type] = true
		end
	end
	-- table.sort(lvAttr,function(a, b) return a.refId<b.refId end)
	return lvAttr,exitAtrr
end

-- 获取灵魂目标等级属性
function ModelBadge:GetBadgeTargetAttr()
	self:GetBadgeLvTargetRef()
	local lv = self.level
	local attrMap = {}
	for _, value in ipairs(self.badgeTargetRef) do
		if lv>= value.refId then
			local attrs = self.tarAttrMap[value.refId]
			for _, attr in ipairs(attrs or {}) do
				if attrMap[attr.refId..attr.type] then
					attrMap[attr.refId..attr.type].value = attr.value+attrMap[attr.refId..attr.type].value
				else
					attrMap[attr.refId..attr.type] = {
						refId = attr.refId,
						type = attr.type,
						value = attr.value,
					}
				end
			end
		else
			break
		end
	end
	return attrMap
end
function ModelBadge:GetBadgeLvTargetRef()
	if not self.badgeTargetRef then
		self.badgeTargetRef = {}
		self.tarAttrMap = {}
		local config = GameTable.BadgeCollectRef
		for _, value in pairs(config) do
			table.insert(self.badgeTargetRef,value)
			local attrs = LxDataHelper.ParseAttrList(value.TargetAttr)
			self.tarAttrMap[value.refId] = attrs
		end
		table.sort(self.badgeTargetRef,function(a, b) return a.refId<b.refId end)
	end
	return self.badgeTargetRef,self.tarAttrMap
end
--灵魂配置
function ModelBadge:GetBadgeRefList(page)
	if not self.badgeRefList then
		self.badgePageList = {}
		self.badgeRefList = {}
		local pageMap = {}
		local config = GameTable.BadgeRef
		for _, value in pairs(config) do
			if not self.badgeRefList[value.page] then
				self.badgeRefList[value.page] = {}
			end
			table.insert(self.badgeRefList[value.page],value)
			if not pageMap[value.page] then
				pageMap[value.page] = value.page
				table.insert(self.badgePageList,value.page)
			end
		end
		for _, list in pairs(self.badgeRefList) do
			table.sort(list,function(a, b)
				if a.sort ~= b.sort then
					return a.sort<b.sort
				else
					return a.refId<b.refId
				end
			end)
		end
		table.sort(self.badgePageList, function(a, b)
			return a < b
		end)
	end
	return self.badgeRefList[page],self.badgePageList
end
--获取灵魂道具
function ModelBadge:GetBadgeItemByQuality(quality)
	local itemList = gModelItem:GetBadgeItemList()
	local ItemRef = GameTable.PlayerItemRef
	local list = {}
	local data = nil
	local ref = nil
	for refId, item in pairs(itemList) do
		ref = ItemRef[refId]
		if item.quality == quality then
			data = gModelItem:GetHeroServerDataByRefId(refId)
			-- data.typeDate = tonumber(ref.typeDate)
			data.quality = ref.quality
			data.type = ref.type
			table.insert(list,data)
		end
	end
	-- local aRef = nil
	-- local bRef = nil
	-- local refs = GameTable.BadgeRef
	table.sort(list,function(a, b)
		-- aRef = refs[a.typeDate]
		-- bRef = refs[b.typeDate]
		if a.type ~= b.type then
			return a.type<b.type
		elseif a.quality~=b.quality then
			return a.quality>b.quality
		else
			return a.refId<b.refId
		end
	end)
	return list
end

