-- 获取灵魂礼包配置商店配置
function ModelBadge:GetBadgeGiftShopRef()
	return self._shopGifgRef
end
-- 获取灵魂礼包配置列表
function ModelBadge:GetBadgeGiftRefList()
	if not self._shopGifgRefList then
		local list = {}
		local shopGifgRef = self._shopGifgRef
		if shopGifgRef then
			local type = shopGifgRef.type
			if type and type > 0 then
				for k, v in pairs(GameTable.StoreFixedRef) do
					if v.type == type then
						table.insert(list, v)
					end
				end
				table.sort(list, function(a, b) return a.sequence < b.sequence end)
			end
		end
		self._shopGifgRefList = list
	end
	return self._shopGifgRefList
end
--统计灵魂道具同品质数量
function ModelBadge:BadgeQualityNum()
	local itemList = gModelItem:GetBadgeItemList()
	local qualityNum = {}--统计同品数量
	for refId, value in pairs(itemList) do
		qualityNum[value.quality] = (qualityNum[value.quality] or 0) + value.num
