--灵魂激活红点
function ModelBadge:BadgeActivateRed(refId)
	local config = GameTable.BadgeRef[refId]
	if not config or self:GetBadgeInfo(refId) then return false end
	local cost = LxDataHelper.ParseItem_4(config.activateCost)
	if cost and gModelGeneral:CheckItemEnough(cost.itemId,cost.itemNum,false) then
		return true
	end
	return false
end

--激活升星红点
function ModelBadge:GetBadgeActivaUpStarRed()
	-- 功能开放
	if not gModelFunctionOpen:CheckIsOpened(37000002,false) then return false end
	local qualityNum = self:BadgeQualityNum()
	local isShow = false
	local badgeRef = GameTable.BadgeRef
	local info
	for _, ref in pairs(badgeRef) do
		if self:BadgeActivateRed(ref.refId) then
			isShow = true
			break
		end
		info = self:GetBadgeInfo(ref.refId)
		if info and info:UpStarRedPoint(qualityNum) then
			isShow = true
			break
		end
	end
	return isShow
end
--可预选奖励红点
function ModelBadge:GetBadgeCallPrepareRed()
	if not gModelFunctionOpen:CheckIsOpened(37000003,false) then return false end
	return not self.selectIndex or self.selectIndex==0
end

--预选奖可领取红点
function ModelBadge:GetBadgeCallPrepareRwdRed()
	if not gModelFunctionOpen:CheckIsOpened(37000003,false) then return false end
	local rwdCondi = LxDataHelper.ParseItem_4(GameTable.BadgeConfigRef.badgeRewardCost)
	local hasNum = gModelItem:GetNumByRefId(rwdCondi.itemId)
	local condiNum = rwdCondi.itemNum
	return hasNum>condiNum
end

--免费召唤红点
function ModelBadge:GetBadgeCallFreeRed()
	if not gModelFunctionOpen:CheckIsOpened(37000003,false) then return false end
	local baseFreeNum = GameTable.BadgeConfigRef.badgeFreeRefNum or 0
	local freeNum = math.max(baseFreeNum - self.free,0)
	return freeNum>0
end
--分页红点
function ModelBadge:GetBadgeActivaUpStarRedByPage(qualityNum,page)
	local list = self:GetBadgeRefList(page)
	for _, ref in ipairs(list) do
		if self:BadgeActivateRed(ref.refId) then
			return true
		end
		local info = self:GetBadgeInfo(ref.refId)
		if info and info:UpStarRedPoint(qualityNum) then
			return true
		end
	end
	return false
end
--穿戴红点
function ModelBadge:GetBadgeWearRed(heroId,type)
	local isOpen = self:CheckBadgeOpen()
	if not isOpen then return false end

	if not self:CheckIsCanWear(heroId) then return false end

	local voidPos = false
	local badges = self:GetHeroWearBadges(heroId) or {}
	for i = 1, 8 do
		local isLock= self:IsLockBadgeSlot(heroId,type or 1,i)
		if not badges[i] and isLock then
			voidPos = true
			break
		end
	end
	local hasCanwear = self:HasCanWearBadge(heroId)
	return voidPos and hasCanwear
end

-- true: 表示礼包存在红点
function ModelBadge:HadShopGiftRed()
	local shopId = self._shopGifgRef.refId
	local isOpened = gModelFunctionOpen:CheckIsOpened(37000004)

	if not isOpened then
		return false
	end

	local refList = self:GetBadgeGiftRefList()
	for k, ref in ipairs(refList) do
		local goods = gModelShop:GetShopItemCfg(ref.refId)

		if goods.price and goods.price.itemNum == 0 then
			-- 免费
			local goodsId = ref.refId
			local itemdata = gModelShop:GetShopItemNetData(shopId, goodsId)
			if itemdata then
				local maxNum = goods.limitCount and goods.limitCount.itemNum or 0
				local hasBuyNum = itemdata:GetHasBuyNum()
				if hasBuyNum < maxNum then
					return true
				end
			end
		end
	end
	return false
end

function ModelBadge:CheckBadgeOpen()
	return gModelFunctionOpen:CheckIsOpened(37000001)
end

---@return boolean 是否可穿戴
function ModelBadge:CheckIsCanWear(heroId)
	local heroSerData = gModelHero:GetHeroServerDataById(heroId)
	if not heroSerData then return false end
	return self:CheckHeroMaxStarCanWear(heroSerData.refId)
end

function ModelBadge:CheckHeroMaxStarCanWear(refId)
	local heroRef = gModelHero:GetHeroRef(refId)
	local maxStar = heroRef and heroRef.maxStar or 0
	return GameTable.BadgeConfigRef.badgeShow <= maxStar
end

function ModelBadge:CheckHeroHasRP(heroId)
	if not self:CheckBadgeOpen() then return false end
	if self:CheckIsCanWear(heroId) and self:GetBadgeWearRed(heroId) then
		return true
	end
	return false
end

return ModelBadge